class MockResponse:
    def __init__(self, status, body):
        self.status_code = status
        self._body = body
    def json(self):
        return self._body

def handle(resp):
    if resp.status_code == 200:
        return ('ok', resp.json())
    if 400 <= resp.status_code < 500:
        return ('client_error', resp.status_code)
    return ('server_error', resp.status_code)
print(handle(MockResponse(200, {'id':'C1'})))
print(handle(MockResponse(400, {})))
print(handle(MockResponse(503, {})))

def should_retry(status):
    return status >= 500 or status == 429
print(should_retry(503), should_retry(400), should_retry(200))

