cache = {}

def get_city(city, fetch):
    if city in cache:
        return cache[city], True
    val = fetch(city)
    cache[city] = val
    return val, False
print(get_city('Lima', lambda c: {'lat': -12.04}))
print(get_city('Lima', lambda c: {'lat': 0}))  # cache hit

