def backoff(attempt):
    return min(2 ** attempt, 8)
print([backoff(i) for i in range(4)])

from datetime import datetime, timezone
def min_provenance(url, status, cache_hit):
    return {
        'source_url': url,
        'fetched_at': '2026-07-20T00:00:00Z',
        'status_code': status,
        'cache_hit': cache_hit,
    }
print(min_provenance('https://example.invalid/geo', 200, False))

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return (local_body, 'offline')
    if status == 200:
        return ({'online': True}, 'live')
    return (None, 'client_error')
print(fetch_with_fallback(503, {'cached': 1}))
print(fetch_with_fallback(200, {}))

import re
def normalize_address(s: str) -> str:
    s = re.sub(r'\s+', ' ', s.strip())
    return s.title()
print(normalize_address('  av.  larco  123  '))

class MockGeocoder:
    TABLE = {'Lima': (-12.0464, -77.0428), 'Arequipa': (-16.4090, -71.5375)}
    def geocode(self, city: str):
        coords = self.TABLE.get(city.title())
        if not coords:
            return None
        lat, lon = coords
        return {'city': city.title(), 'lat': lat, 'lon': lon, 'provider': 'mock'}
print(MockGeocoder().geocode('lima'))

def allowed_for_public_geocoder(payload):
    forbidden = {'document_id', 'api_token', 'password', 'full_address_line2'}
    if any(k in payload for k in forbidden):
        return False
    # solo requests conceptuales de ciudad / address corta
    return set(payload).issubset({'city', 'country', 'query'})
print(allowed_for_public_geocoder({'city': 'Lima'}))
print(allowed_for_public_geocoder({'document_id': 'DNI'}))

def valid_coord(lat, lon):
    return -90 <= lat <= 90 and -180 <= lon <= 180
print(valid_coord(-12.04, -77.04), valid_coord(91, 0))
